from dataclasses import dataclass
from datetime import datetime
from enum import Enum

class AlertStage(str, Enum):
    WARNING  = "warning"   # 80% elapsed, no first response
    BREACHED = "breached"  # 100% elapsed, no first response
    EXTENDED = "extended"  # 150% elapsed, still no response

class Priority(str, Enum):
    P0 = "P0"; P1 = "P1"; P2 = "P2"; P3 = "P3"

# First-response SLA windows in hours per priority
RESPONSE_SLA: dict[Priority, float] = {
    Priority.P0: 1.0,
    Priority.P1: 2.0,
    Priority.P2: 4.0,
    Priority.P3: 8.0,
}

@dataclass
class BreachAlert:
    ticket_id: str
    priority: Priority
    stage: AlertStage
    assigned_agent: str
    is_enterprise: bool
    account_id: str | None

    def notify_targets(self) -> list[str]:
        targets = ["#support-alerts"]
        match self.stage:
            case AlertStage.WARNING:
                targets.append(f"@{self.assigned_agent}")
            case AlertStage.BREACHED:
                targets.extend(["#support-management", f"@{self.assigned_agent}"])
                if self.is_enterprise:
                    targets.append("#enterprise-success")
            case AlertStage.EXTENDED:
                targets.extend([
                    "#support-management",
                    "#vp-engineering",
                ])
                if self.is_enterprise and self.account_id:
                    targets.append(f"account-executive:{self.account_id}")
        return targets

    def requires_reassignment(self) -> bool:
        # Auto-reassign on breach; extended breach triggers manager assignment
        return self.stage in (AlertStage.BREACHED, AlertStage.EXTENDED)

    def customer_update_required(self) -> bool:
        return self.stage in (AlertStage.BREACHED, AlertStage.EXTENDED)

from dataclasses import dataclass
from datetime import datetime
from enum import Enum

class IncidentState(str, Enum):
    NONE    = "none"
    ACTIVE  = "active"
    COOLING = "cooling"  # incident resolved but still monitoring

@dataclass
class BreachEscalationContext:
    ticket_id: str
    priority: str
    incident_state: IncidentState
    incident_id: str | None

    def escalation_channel(self) -> str:
        if self.incident_state == IncidentState.ACTIVE:
            # During active incident, P0 breaches go to incident channel
            # Lower priorities go to backup queue silently
            if self.priority == "P0":
                return f"#incident-{self.incident_id}"
            return "#support-backup-queue"
        # Normal operation
        return "#support-management"

    def should_suppress_hard_alert(self) -> bool:
        # Suppress hard alerts for P2/P3 during active incident
        # to avoid flooding the on-call team
        return (
            self.incident_state == IncidentState.ACTIVE
            and self.priority in ("P2", "P3")
        )

    def customer_message_template(self) -> str:
        if self.incident_state == IncidentState.ACTIVE:
            return (
                "We are currently investigating a service disruption that may be "
                "affecting your request. Our team is actively working on resolution. "
                "We will provide an update within the next [interval]. Current status "
                "is available at status.anthropic.com."
            )
        return (
            "We apologize for the delayed response to your support request. "
            "A member of our team is now reviewing your issue and will respond "
            "with an update shortly."
        )

from dataclasses import dataclass
from datetime import datetime

@dataclass
class AccountTeamBriefing:
    account_id: str
    account_name: str
    ticket_id: str
    priority: str
    breach_at: datetime
    breach_duration_minutes: float
    root_cause_summary: str    # filled after post-breach review
    credit_owed_pct: float
    recommended_message: str   # drafted by support manager for AE to personalise

    def urgency_flag(self) -> str:
        if self.priority == "P0" and self.breach_duration_minutes > 60:
            return "CRITICAL"
        if self.priority in ("P0", "P1"):
            return "HIGH"
        return "STANDARD"

    def ae_talking_points(self) -> list[str]:
        points = [
            f"We experienced a {self.breach_duration_minutes:.0f}-minute delay in responding to your {self.priority} issue.",
            f"Root cause: {self.root_cause_summary}",
        ]
        if self.credit_owed_pct > 0:
            points.append(
                f"A service credit of {self.credit_owed_pct*100:.0f}% will be applied to your next invoice — no action required from you."
            )
        points.append(
            "We have completed a post-breach review and implemented [corrective action] to prevent recurrence."
        )
        return points
